<template>
<div id="app" :class="typeof weather.main != 'undefined' && weather.main.temp > 16 ? 'warm' : ''">
  <head>
    <title>Weather App</title>
  </head>
  <main>
    <div class="search-box">
      <v-toolbar flat app class="search-bar">
        <v-toolbar-title>
          <input
            type="text"
            placeholder="Search..."
            v-model="query"
            @keypress="fetchWeather"
          />
        </v-toolbar-title>
        <v-spacer></v-spacer>
        <v-btn float v-on:click="co">Enter</v-btn>
      </v-toolbar>
      <!--         <input 
          type="text" 
          class="search-bar" 
          placeholder="Search..."
          v-model="query"
          @keypress="fetchWeather"
        />
      <v-btn fab depressed v-on:click="co" class="btn"> Enter</v-btn>-->
    </div>

    <div class="weather-wrap" v-if="typeof weather.main != 'undefined'">
      <div class="location-box">
        <div class="location">{{ weather.name }}, {{ weather.sys.country }}</div>
        <div class="date">{{ dateBuilder() }}</div>
        <div class="date"><p>Local time: {{timebuilder()}}</p></div>
      </div>

      <div class="weather-box">
        <div class="temp">{{ Math.round(weather.main.temp) }}°c</div>
        <div class="weather">{{ weather.weather[0].main }}</div>
      </div>
      <div id="adsgoeshere" style="background: #1d1f29; padding-top:60px; text-align: center;" v-html="adsenseContent"></div>
    </div>
  </main>
</div>
</template>

<script>
export default {
  name: "app",

  data() {
    return {
      api_key: "9ababd250134483dc5948bc381026d95",
      url_base: "https://api.openweathermap.org/data/2.5/",
      query: "",
      weather: {},
      counter: 1,
      adsenseContent: ''
    };
  },
  methods: {
    fetchWeather(e) {
      if (e.key == "Enter") {
        fetch(
          `${this.url_base}weather?q=${this.query}&units=metric&APPID=${this.api_key}`
        )
          .then(res => {
            return res.json();
          })
          .then(this.setResults);
      }
    },
    setResults(results) {
      this.weather = results;
    },
    mounted() {
        this.adsenseContent = document.getElementById('divadsensedisplaynone').innerHTML;
    },

    co() {
      {
        fetch(
          `${this.url_base}weather?q=${this.query}&units=metric&APPID=${this.api_key}`
        )
          .then(res => {
            return res.json();
          })
          .then(this.setResults);
      }
    },
    timebuilder() {
      let time = new Date();
      let hours = time.getHours();
      let mins = time.getMinutes();
      let am = "AM";
      if(hours >= 12){
        hours = hours - 12;
        am = "PM"
      }
      
      if(mins < 10){
        mins = "0" + mins.toString();
        return `${hours}:${mins} ${am}`
      }

      else{
        return `${hours}:${mins} ${am}`
      }
      

    },
    dateBuilder() {
      let d = new Date();
      let months = [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December"
      ];
      let days = [
        "Sunday",
        "Monday",
        "Tuesday",
        "Wednesday",
        "Thursday",
        "Friday",
        "Saturday"
      ];
      let day = days[d.getDay()];
      let date = d.getDate();
      console.log(d.getMonth());
      let month = months[d.getMonth()];
      let year = d.getFullYear();
      return `${day}, ${month} ${date}, ${year}`;
    }
  }
};
</script>

